payload.raw:
{
  "layout": "cards-3-featured",
  "title": "自研高精度柔性传感器",
  "subtitle": "",
  "cards": [
    {
      "icon": "target",
      "heading": "仿生液态金属材料",
      "body": "采用仿生“水膜-鱼网”结构液态金属导电薄膜与低迟滞聚氨酯复合介质，实现应变系数＞80的高灵敏度。材料在10万次弯折后性能衰减＜5%，循环寿命较传统方案提升3倍，保障了传感器的长期稳定性和耐用性。"
    },
    {
      "icon": "globe",
      "heading": "光纤-IMU混合架构",
      "body": "融合光纤微形变检测与IMU姿态补偿，攻克单一传感漂移缺陷。该架构达成0.1mm空间分辨率与＜50ms系统延迟，实现了高精度动态形变与姿态的同步感知，为复杂应用场景提供了可靠数据基础。"
    },
    {
      "icon": "code",
      "heading": "成本与成果",
      "body": "整体方案成本较进口方案降低超50%，有力支撑“传感器成本优化”目标。关键材料与结构设计发表于IEEE Transactions on Electron Devices（2023）及IEEE Sensors Journal（2024），获领域内学者引用验证其工程适用性。"
    }
  ]
}

